import React, { useState } from 'react';
import { View, StyleSheet, TouchableOpacity, Text } from 'react-native';

const TabBar = () => {
  const [activeTab, setActiveTab] = useState('Tab1');

  const handleTabPress = (tabName) => {
    setActiveTab(tabName);
  };

  return (
    <View style={styles.tabBar}>
      <TouchableOpacity
        style={[styles.tabItem, activeTab === 'Tab1' && styles.activeTabItem]}
        onPress={() => handleTabPress('Tab1')}
      >
        <Text style={styles.tabText}>Tab 1</Text>
      </TouchableOpacity>
      <TouchableOpacity
        style={[styles.tabItem, activeTab === 'Tab2' && styles.activeTabItem]}
        onPress={() => handleTabPress('Tab2')}
      >
        <Text style={styles.tabText}>Tab 2</Text>
      </TouchableOpacity>
      <TouchableOpacity
        style={[styles.tabItem, activeTab === 'Tab3' && styles.activeTabItem]}
        onPress={() => handleTabPress('Tab3')}
      >
        <Text style={styles.tabText}>Tab 3</Text>
      </TouchableOpacity>
    </View>
  );
};

const styles = StyleSheet.create({
  tabBar: {
    flexDirection: 'row',
    backgroundColor: '#f2f2f2',
    height: 50,
    justifyContent: 'space-around',
    alignItems: 'center',
  },
  tabItem: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  activeTabItem: {
    backgroundColor: '#ddd',
  },
  tabText: {
    fontSize: 16,
    fontWeight: 'bold',
  },
});

export default TabBar;
